mapper.select:
SELECT 
FROM score s
LEFT JOIN student st ON s.student_id = st.id
LEFT JOIN class_entity c ON s.class_id = c.id
LEFT JOIN sys_user u1 ON s.input_user_id = u1.id
LEFT JOIN sys_user u2 ON s.update_user_id = u2.id
WHERE s.is_deleted = 0

    AND s.class_id = #{classId}


    AND s.student_id = #{studentId}


    AND s.subject = #{subject}


    AND s.exam_name = #{examName}

ORDER BY s.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM score s
WHERE s.is_deleted = 0

    AND s.class_id = #{classId}


    AND s.student_id = #{studentId}


    AND s.subject = #{subject}


    AND s.exam_name = #{examName}

SELECT id, student_id, subject, exam_name, score
FROM score
WHERE student_id = #{studentId}
AND subject = #{subject}
AND exam_name = #{examName}
AND is_deleted = 0
LIMIT 1

SELECT COUNT(*) as totalCount, ROUND(AVG(score), 2) as avgScore, MAX(score) as maxScore, MIN(score) as minScore, SUM(CASE WHEN score >= pass_score THEN 1 ELSE 0 END) as passCount, CASE WHEN COUNT(*) > 0 THEN ROUND(SUM(CASE WHEN score >= pass_score THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) ELSE 0 END as passRate, SUM(CASE WHEN score >= (full_score * 0.9) THEN 1 ELSE 0 END) as excellentCount, CASE WHEN COUNT(*) > 0 THEN ROUND(SUM(CASE WHEN score >= (full_score * 0.9) THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) ELSE 0 END as excellentRate FROM score WHERE class_id = #{classId} AND is_deleted = 0
AND subject = #{subject}
AND exam_name = #{examName}

SELECT CASE WHEN score >= (full_score * 0.9) THEN '90-100' WHEN score >= (full_score * 0.8) THEN '80-89' WHEN score >= (full_score * 0.7) THEN '70-79' WHEN score >= (full_score * 0.6) THEN '60-69' ELSE '0-59' END as scoreRange, COUNT(*) as count, ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM score WHERE class_id = #{classId} AND is_deleted = 0
AND subject = #{subject}
AND exam_name = #{examName}
), 2) as percentage FROM score WHERE class_id = #{classId} AND is_deleted = 0
AND subject = #{subject}
AND exam_name = #{examName}
GROUP BY CASE WHEN score >= (full_score * 0.9) THEN '90-100' WHEN score >= (full_score * 0.8) THEN '80-89' WHEN score >= (full_score * 0.7) THEN '70-79' WHEN score >= (full_score * 0.6) THEN '60-69' ELSE '0-59' END ORDER BY scoreRange DESC
